  "code": "def check_dict_case(dict):
    """
    For a dictionary input, output True when every key is a string that shares the same case (all lower or all upper), and output False in all other situations, such as when the dictionary is empty or has non-string keys.

    Examples:
    check_dict_case({"a":"apple", "b":"banana"}) should return True.
    check_dict_case({"a":"apple", "A":"banana", "B":"banana"}) should return False.
    check_dict_case({"a":"apple", 8:"banana", "a":"apple"}) should return False.
    check_dict_case({"Name":"John", "Age":"36", "City":"Houston"}) should return False.
    check_dict_case({"STATE":"NC", "ZIP":"12345" }) should return True.
    """
    if not dict:
        return False

    cases = set()
    for key in dict.keys():
        if not isinstance(key, str):
            return False
        if key.islower():
            cases.add('lower')
        elif key.isupper():
            cases.add('upper')
        else:
            return False

    return len(cases) == 1",
